const body = $input.first().json || {};

const full_name = (body.full_name || body.name || '').trim();
const email = (body.email || '').toLowerCase().trim();
const phone_raw = (body.phone || body.phone_number || '').trim();
const property_value = body.property_value || body.budget || 'undisclosed';
const source = body.source || body.utm_source || 'direct';

// Hard contract: must have a name and at least one contact method
if (!full_name) throw new Error('SCHEMA_INVALID: full_name is required');
if (!email && !phone_raw) throw new Error('SCHEMA_INVALID: phone or email required');

// Deterministic lead_id for idempotency (email+timestamp bucketed to 5min to catch double-submits)
const bucket = Math.floor(Date.now() / 300000);
const dedup_key = `${email || phone_raw}_${bucket}`;
const lead_id = `lead_${Date.now()}_${Math.random().toString(36).slice(2,8)}`;

return [{ json: {
  full_name,
  email,
  phone_raw,
  property_value,
  source,
  lead_id,
  dedup_key,
  submitted_at: new Date().toISOString()
}}];

const d = $input.first().json;

// E.164 FIX: strip spaces, dashes, parens, dots ONLY â€” NOT the +
let phone = d.phone_raw.replace(/[\s\-().]/g, '').trim();

// Auto-detect and fix common formats
if (phone && !phone.startsWith('+')) {
  if (phone.startsWith('1') && phone.length === 11) {
    phone = '+' + phone; // US with country code, no +
  } else if (phone.length === 10) {
    phone = '+1' + phone; // US 10-digit, no country code
  } else {
    phone = '+' + phone; // Unknown international â€” prepend + and let Abstract validate
  }
}

// Quick pre-flight format check before sending to Abstract API
const phone_format_ok = /^\+[1-9]\d{7,14}$/.test(phone);
const email_format_ok = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(d.email);

// LEAD SCORING (0-100)
let score = 0;
const pv = parseFloat(String(d.property_value).replace(/[^0-9.]/g, '')) || 0;
if (pv >= 5000000) score += 50;
else if (pv >= 2000000) score += 35;
else if (pv >= 1000000) score += 25;
else if (pv >= 500000) score += 15;
else score += 5;

const premiumSources = ['referral', 'google_ads', 'facebook_ads', 'linkedin'];
if (premiumSources.includes(d.source)) score += 20; else score += 5;
if (phone && phone_format_ok) score += 15;
if (d.email && email_format_ok) score += 10;

const lead_tier = score >= 70 ? 'A' : score >= 45 ? 'B' : 'C';

return [{ json: {
  ...d,
  phone,
  phone_format_ok,
  email_format_ok,
  lead_score: Math.min(score, 100),
  lead_tier
}}];

const lead = $('Normalize & Score Lead').first().json;
const v = $input.first().json || {};

// Prefer Abstract's formatted number (already correct E.164) over our normalized version
const phone_e164 = (v.format && v.format.international) ? v.format.international : lead.phone;

return [{ json: {
  ...lead,
  phone_e164,
  phone_verified: v.valid === true,
  phone_is_mobile: (v.type || '').toLowerCase().includes('mobile'),
  phone_carrier: (v.carrier && v.carrier.name) ? v.carrier.name : 'Unknown',
  phone_country_code: (v.country && v.country.code) ? v.country.code : 'Unknown'
}}];

const lead = $input.first().json;
const tz = $env.BUSINESS_TIMEZONE || 'America/New_York';
const now = new Date();
const localStr = now.toLocaleString('en-US', { timeZone: tz });
const local = new Date(localStr);
const hour = local.getHours();
const day = local.getDay(); // 0=Sun, 6=Sat

const isWeekday = day >= 1 && day <= 5;
const isSaturday = day === 6;
const isWeekdayHours = isWeekday && hour >= 9 && hour < 20;
const isSaturdayHours = isSaturday && hour >= 10 && hour < 16;
const can_call_now = isWeekdayHours || isSaturdayHours;

// Calculate next business open time if outside hours
let resume_at = null;
if (!can_call_now) {
  const next = new Date(local);
  let openHour = isSaturday ? 10 : 9;
  next.setHours(openHour, 0, 0, 0);
  if (hour >= 20 || (isSaturday && hour >= 16)) next.setDate(next.getDate() + 1);
  // Skip Sunday
  if (next.getDay() === 0) next.setDate(next.getDate() + 1);
  if (next.getDay() === 6) openHour = 10; else openHour = 9;
  next.setHours(openHour, 0, 0, 0);
  resume_at = next.toISOString();
}

return [{ json: { ...lead, can_call_now, resume_at } }];

