const rawText = ($input.first().json.text || '').trim();
const lead = $('Check Business Hours').first().json;

let html = rawText;

// Strip markdown code fences regardless of language tag
html = html.replace(/```[a-z]*\s*/gi, '').replace(/```/g, '').trim();

// Strip any conversational preamble before the first HTML tag
const firstTagIdx = html.indexOf('<');
if (firstTagIdx > 0) {
  html = html.slice(firstTagIdx);
}

// VALIDATION CHECKS
const hasHtmlTag = /<[a-z][^>]*>/i.test(html);
const minLength = html.length >= 50;
const maxLength = html.length <= 6000;
const firstName = lead.full_name.split(' ')[0];

if (!hasHtmlTag || !minLength) {
  // LLM output is garbage â€” use bulletproof static fallback
  console.warn(`LLM_SANITIZE_FALLBACK: Output failed validation. Length=${html.length}, hasHtml=${hasHtmlTag}`);
  html = `<p>Dear ${firstName},</p>
<p>Thank you for reaching out about your property interest at the <strong>$${lead.property_value}</strong> level. We work with a select group of clients and would love to understand your goals better.</p>
<p>I'd suggest a brief 15-minute strategy call â€” please book at a time that suits you below.</p>`;
}

if (!maxLength) {
  html = html.slice(0, 5800) + '</p>';
}

return [{ json: { sanitized_html: html, first_name: firstName, email: lead.email, property_value: lead.property_value, lead_id: lead.lead_id } }];

